from typing import Optional, Tuple

def parse_monto(raw: str) -> Tuple[bool, Optional[int], Optional[str]]:
    t = raw.strip()
    try:
        n = int(t)
    except ValueError:
        return False, None, f"no int: {raw!r}"
    if n < 0:
        return False, None, f"negativo: {n}"
    return True, n, None

for v in ["0", "10", "-1", "x"]:
    print(v, parse_monto(v))

